parameters.jsonBody:
={
  "model": "sora-2",
  "prompt": "SELFIE VIDEO — front-facing phone camera held by the person at arm's length, slightly above eye level. The person shown in the reference image is recording themselves in selfie mode. They are looking directly into the camera lens, speaking in {{ $('Merge Avatar + Video Data').item.json.language }}, and holding/using the product in their other hand. The product must be clearly visible in frame. Handheld camera shake, natural lighting, real-world setting. {{ JSON.stringify($('Merge Avatar + Video Data').item.json.videoPrompt).slice(1, -1) }}",
  "input_reference": {
    "image_url": "{{ $('Merge Avatar + Video Data').item.json.avatarImageUrl }}"
  },
  "size": "720x1280",
  "seconds": "12"
}

={
  "video": {
    "id": "{{ $json.latestVideoId }}"
  },
  "prompt": "Continue this selfie video seamlessly. MAINTAIN: front-facing selfie camera angle held by the person, direct eye contact with the lens, the product clearly visible and being used/demonstrated in the other hand, person speaking in {{ $json.language }}. The camera stays in selfie POV at all times — never switch to third person. {{ JSON.stringify($json.videoPrompt).slice(1, -1) }}",
  "seconds": "8"
}

={
  "contents": [{
    "parts": [
      {"inline_data": {"mime_type": "image/jpeg", "data": "{{ $json.imageBase64 }}"}},
      {"text": "The image above is the EXACT product that must appear in this photo. Generate a photorealistic portrait photo, exactly 720x1280 pixels, 9:16 aspect ratio. {{ JSON.stringify($('Generate Avatar Prompt (GPT-4o)').item.json.message.content).slice(1, -1) }} CRITICAL: The person MUST be holding this EXACT product from the reference image above — replicate its colors, packaging, label text, and design with complete accuracy."}
    ]
  }],
  "generationConfig": {
    "responseModalities": ["TEXT", "IMAGE"],
    "imageConfig": {
      "aspectRatio": "9:16"
    }
  }
}

parameters.jsCode:
const response = $input.first().json;
const parts = response.candidates[0].content.parts;
const imagePart = parts.find(p => p.inlineData);
if (!imagePart) throw new Error('No image data in Gemini response');
const b64 = imagePart.inlineData.data;
const mimeType = imagePart.inlineData.mimeType || 'image/png';
return [{
  json: { mimeType },
  binary: {
    data: {
      data: b64,
      mimeType: mimeType,
      fileName: 'avatar.png',
      fileExtension: 'png'
    }
  }
}];

